window.BEINVT_QR_FALLBACK = {
  draw: function(canvas, text){
    var ctx = canvas.getContext('2d');
    var size = canvas.width = canvas.height = 220;
    ctx.fillStyle = '#fff'; ctx.fillRect(0,0,size,size);
    ctx.fillStyle = '#000';
    function sq(x,y,w){ctx.fillRect(x,y,w,w);}
    function finder(x,y){ctx.fillStyle='#000'; sq(x,y,42); ctx.fillStyle='#fff'; sq(x+7,y+7,28); ctx.fillStyle='#000'; sq(x+14,y+14,14);}
    finder(8,8); finder(170,8); finder(8,170);
    var seed=0, s=String(text||'');
    for(var i=0;i<s.length;i++) seed=((seed*31)+s.charCodeAt(i))>>>0;
    ctx.fillStyle='#000';
    for(var yy=0; yy<25; yy++) for(var xx=0; xx<25; xx++){var px=20+xx*7, py=20+yy*7; if((px<60&&py<60)||(px>160&&py<60)||(px<60&&py>160)) continue; seed=(seed*1664525+1013904223)>>>0; if(seed&1) ctx.fillRect(px,py,6,6);}
    ctx.fillStyle='#000'; ctx.font='10px Arial'; ctx.fillText('LOCAL FALLBACK',70,214);
  }
};
